def perceive(data):
    risk = None
    if isinstance(data, dict):
        risk = data.get("risk")
    else:
        text = str(data)
        if "risk" in text:
            tail = text.split("risk", 1)[1]
            digits = ""
            for ch in tail:
                if ch.isdigit():
                    digits += ch
                elif digits:
                    break
            if digits:
                risk = int(digits)
    if risk is None:
        return {}
    risk = max(0, min(100, int(risk)))
    return {"current_risk": risk}
